tool.command:

python $__tool_directory__/flux_to_map.py

--tool_dir $__tool_directory__
--out_log $log

#if $cond.type_selector != 'user_fluxes':
	--option $cond.type_selector
	--color_map $cond.color_map
#end if

#if $cond.type_selector == 'datasets':

	--input_datas_fluxes
	#for $data in $cond.input_datasets_fluxes:
		${data.input_fluxes}
	#end for

	--names_fluxes
	#for $data in $cond.input_datasets_fluxes:
		${data.input_name_fluxes}
	#end for

	--comparison ${cond.comparis.comparison}
	#if $cond.comparis.comparison == 'onevsmany'
		--control '${cond.comparis.controlgroup}'
	#end if

	#if $cond.advanced.choice == 'true':
		--test ${cond.advanced.test}
		--pValue ${cond.advanced.pValue}
		--adjusted ${cond.advanced.adjusted}
		--fChange ${cond.advanced.fChange}
		--generate_svg ${cond.advanced.generateSvg}
		--generate_pdf ${cond.advanced.generatePdf}
	#else
		--test 'ks'
		--pValue 0.05
		--adjusted false
		--fChange 1.2
		--generate_svg false
		--generate_pdf true
	#end if

#elif $cond.type_selector == 'dataset_class':

	--input_data_fluxes $cond.input_data_fluxes
	--input_class_fluxes $cond.input_class_fluxes

	--comparison ${cond.comparis.comparison}
	#if $cond.comparis.comparison == 'onevsmany'
		--control '${cond.comparis.controlgroup}'
	#end if

	#if $cond.advanced.choice == 'true':
		--test ${cond.advanced.test}
		--pValue ${cond.advanced.pValue}
		--adjusted ${cond.advanced.adjusted}
		--fChange ${cond.advanced.fChange}
		--generate_svg ${cond.advanced.generateSvg}
		--generate_pdf ${cond.advanced.generatePdf}
	#else
		--test 'ks'
		--pValue 0.05
		--adjusted false
		--fChange 1.2
		--generate_svg false
		--generate_pdf true
	#end if

#elif $cond.type_selector == 'user_fluxes':
	--user_fluxes ${cond.user_fluxes_file}
	--generate_svg ${cond.generateSvg}
	--generate_pdf ${cond.generatePdf}
	--pValue ${cond.pValue}
	--fChange ${cond.fChange}
	--test 'ks'
	--adjusted false

#end if

--choice_map '${cond_choice_map.choice_map}'
#if $cond_choice_map.choice_map == 'Custom':
	--custom_map ${cond_choice_map.custom_map}
#end if
